const normalizeWebappDocsArticleSlug = (slug: string): string => {
	const trimmedSlug = slug.trim();
	if (!trimmedSlug || trimmedSlug === "/") {
		return "/";
	}

	const withLeadingSlash = trimmedSlug.startsWith("/")
		? trimmedSlug
		: "/" + trimmedSlug;
	let withoutTrailingSlash = withLeadingSlash;
	while (
		withoutTrailingSlash.length > 1 &&
		withoutTrailingSlash.endsWith("/")
	) {
		withoutTrailingSlash = withoutTrailingSlash.slice(0, -1);
	}

	return withoutTrailingSlash || "/";
};

const getWebappDocsArticleBySlug = (
	slug: string,
	locale: AppLocale = "fr",
): WebappDocsArticle | null => {
	const normalizedSlug = normalizeWebappDocsArticleSlug(slug);
	return locale === "en"
		? WEBAPP_DOCS_ARTICLES_BY_SLUG_EN[normalizedSlug] ?? null
		: WEBAPP_DOCS_ARTICLES_BY_SLUG[normalizedSlug] ?? null;
};

const WEBAPP_DOCS_ARTICLE_SLUGS = Object.keys(WEBAPP_DOCS_ARTICLES_BY_SLUG);

export {
	WEBAPP_DOCS_ARTICLE_SLUGS,
	WEBAPP_DOCS_ARTICLES_BY_SLUG,
	getWebappDocsArticleBySlug,
	normalizeWebappDocsArticleSlug,
};

export type { WebappDocsArticle };
